import React, { useState } from "react";
import {
  Button,
  Typography,
  Box,
  Grid,
  TextField,
  Card,
  CardContent,
} from "@mui/material";
import PhotoCamera from "@mui/icons-material/PhotoCamera";
import UploadFileIcon from "@mui/icons-material/UploadFile";

export default function DocumentUpload() {
  const [form, setForm] = useState({
    licenseNumber: "",
    rcNumber: "",
    insuranceNumber: "",
    aadharFrontNumber: "",
    aadharBackNumber: "",
    licenseImage: null,
    rcImage: null,
    insuranceImage: null,
    aadharFront: null,
    aadharBack: null,
  });

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleFile = (field, file) => {
    setForm({ ...form, [field]: file });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log("📌 Submitted data:", form);
  };

  const DocumentRow = ({ label, name, fileField }) => (
    <Card sx={{ mb: 3, borderRadius: 2, boxShadow: 2 }}>
      <CardContent>
        <Grid container spacing={2} alignItems="center">
          {/* Left: Number Field */}
          <Grid item xs={12} md={6}>
            <TextField
              fullWidth
              label={`${label} Number`}
              name={name}
              value={form[name]}
              onChange={handleChange}
            />
          </Grid>

          {/* Right: Upload + Camera */}
          <Grid item xs={12} md={6}>
            <Typography variant="subtitle2" sx={{ mb: 1 }}>
              {label} Image
            </Typography>
            <Box sx={{ display: "flex", gap: 2, alignItems: "center" }}>
              <Button
                component="label"
                variant="outlined"
                startIcon={<UploadFileIcon />}
              >
                Upload
                <input
                  type="file"
                  hidden
                  onChange={(e) => handleFile(fileField, e.target.files[0])}
                />
              </Button>
              <Button
                variant="contained"
                color="secondary"
                startIcon={<PhotoCamera />}
              >
                Camera
              </Button>
            </Box>
            {form[fileField] && (
              <Typography variant="body2" sx={{ mt: 1, color: "green" }}>
                📂 {form[fileField].name}
              </Typography>
            )}
          </Grid>
        </Grid>
      </CardContent>
    </Card>
  );

  return (
    <Box sx={{ p: 4 }}>
      <Typography
        variant="h4"
        sx={{ textAlign: "center", fontWeight: "bold", mb: 4 }}
      >
        Document Verification
      </Typography>

      <form onSubmit={handleSubmit}>
        <DocumentRow
          label="Driving License"
          name="licenseNumber"
          fileField="licenseImage"
        />
        <DocumentRow label="RC" name="rcNumber" fileField="rcImage" />
        <DocumentRow
          label="Insurance"
          name="insuranceNumber"
          fileField="insuranceImage"
        />
        <DocumentRow
          label="Aadhar (Front)"
          name="aadharFrontNumber"
          fileField="aadharFront"
        />
        <DocumentRow
          label="Aadhar (Back)"
          name="aadharBackNumber"
          fileField="aadharBack"
        />

        <Box sx={{ textAlign: "center", mt: 4 }}>
          <Button
            type="submit"
            variant="contained"
            sx={{
              bgcolor: "black",
              color: "white",
              px: 4,
              py: 1.2,
              fontWeight: "bold",
              borderRadius: 2,
              "&:hover": { bgcolor: "#333" },
            }}
          >
            Submit Documents
          </Button>
        </Box>
      </form>
    </Box>
  );
}
